var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"시, 시그마? 아니, 합격한 건 아니지만 실장님이라고 불러야 하나?","JPN":"シ、シグマ？　いや、合格したわけじゃないけど、室長って呼ぶべきかな？","ENG":"S-Sigma? Wait, I didn't get the job yet, but do I still have to call you Chief?","TWN":"西、西格瑪？呃，雖說我還在試用期，但我是不是該叫你室長？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"그것보다 해적이요?","JPN":"それより、海賊？","ENG":"But more importantly, what do you mean \\"pirate\\"?","TWN":"比起這個，海盜又是什麼？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"해적의 필수적인 3요소! 첫째는 보물에 대한 갈망, 둘째는 상황을 타개하는 순발력!","JPN":"海賊の3要素！　一つ、お宝への渇望。二つ、状況を打破する瞬発力！","ENG":"The three essential elements a pirate should have! The first is the yearning for treasure! The second is the quickness to overcome any situation!","TWN":"海盜的三要素！第一是對寶藏的渴望，第二是面對局勢的應變力！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"셋째는…… 음, 그게 그러니까.","JPN":"三つ……えっと、それが。","ENG":"And the third is... Um, well...","TWN":"第三是……嗯，那個，是……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그래, 바다로 나아가고자 하는 용기!","JPN":"そう、海に出ようとする勇気！","ENG":"Right! The courage to sail out to sea!","TWN":"對，勇敢地向大海前進吧！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"넌 그 세 가지를 모두 갖추고 있어!","JPN":"あなたはその三つを全部あわせ持ってる！","ENG":"And you have all three!","TWN":"你擁有那三樣東西！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"일반인들은 몰라도 시그마 선장님만큼은 속일 수 없다!","JPN":"一般人ならともかく、シグマ船長だけは騙せない！","ENG":"You might fool the others, but you can't fool Captain Sigma!","TWN":"普通人或許不知道，但絕對騙不過西格瑪船長！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"선장이라니. 실장님은 코핀 컴퍼니 미래전략실 소속이잖아요?","JPN":"船長って。室長はコフィンカンパニーの未来戦略室所属でしょう？","ENG":"Captain? But you're the head of Coffin Company's Future Strategy Department.","TWN":"船長？你不是科芬公司未來戰略室的負責人嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"어라, 날 알고 있어?","JPN":"あれ、私のことを知ってるの？","ENG":"Huh? You know who I am?","TWN":"咦，你認識我嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"네. 귀사의 요청을 받아 실장님을 모시러 왔습니다.","JPN":"はい。御社から依頼されて室長をお迎えにあがりました。","ENG":"Yes. I was requested by your company to bring you back to the office.","TWN":"沒錯，我是受公司所託來接室長的。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"실장님이 없어서 회사가 난리예요. 빨리 돌아가자고요.","JPN":"室長がいなくて、会社が大変なことになってますよ。早く戻りましょう。","ENG":"The company's a mess without you. Let's go back.","TWN":"室長不在，公司快亂成一團了。請快點回去吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"싫어.","JPN":"イヤだ。","ENG":"No.","TWN":"不要。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"예?","JPN":"はい？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"싫어! 최근에는 일만 엄청 했는걸! 부사장 아줌마는 매번 나한테만 뭐라 하고!","JPN":"イヤ！　最近はめちゃくちゃ働いてたもん！　副社長のおばさんはいつも私にだけ文句を言うの！","ENG":"No! I've been working super hard recently! And the Vice President always nags me!","TWN":"不要！最近一直在拼命工作！副總大嬸總是只針對我！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"난 시그마 해적단의 선장이야. 선장은 보물을 찾아야 한다고!","JPN":"私はシグマ海賊団の船長だよ。船長はお宝を探さないと！","ENG":"I'm the captain of the Sigma Pirates. And the captain is supposed to find treasure!","TWN":"我是西格瑪海盜團的船長。船長就應該去尋找寶藏！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"참고로 뭘 상상하든 그 이상일 겁니다.","JPN":"ちなみに、何を想像しようがそれ以上でしょう。","ENG":"By the way, it will be a lot worse than what you'd expect.","TWN":"順便說一下，情況可能超出你的預期。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아빠랑 떨어졌다는 이유로 최근 반항이 거세졌거든요.","JPN":"パパと引き離されたという理由で、最近激しく抵抗していますので。","ENG":"She's been acting out because she was separated from her \\"daddy.\\"","TWN":"最近因為和爸爸分開，反抗變得更加激烈。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"수많은 육아전문가들도 학을 뗐으니, 각오 단단히 하시길.","JPN":"多くの育児専門家も諦めましたので、しっかりと覚悟してください。","ENG":"Countless child experts got sick of her too, so we hope you're ready.","TWN":"許多育兒專家也束手無策，請做好心理準備。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"곤란한데, 부사장님 이야기가 사실이었잖아?","JPN":"まいったな、副社長の話が本当だったじゃない。","ENG":"I guess the Vice President was right.","TWN":"這下可麻煩了，副總說的是真的吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"여기서는 일단 장단을 맞춰야 하나…?","JPN":"ここではとりあえず相手に合わせるべきか……？","ENG":"Should I just play along for now...?","TWN":"總之先配合她一下嗎……?"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"흐흐흐흐…!","JPN":"ふふふふ……！","ENG":"He he he he...!","TWN":"呵呵、呵呵呵……！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"이렇게 쉽게 속아넘어갈 줄이야! 천하의 시그마 선장도 별거 없구나!","JPN":"こんなに簡単に騙されるなんて！　天下のシグマ船長も大したことなかったね！","ENG":"I can't believe you were fooled so easily! The mighty Captain Sigma isn't so mighty after all!","TWN":"沒想到你這麼容易上當！天下無敵的西格瑪船長也不過如此嘛！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗, 너는 설마…!","JPN":"あっ、あなたはまさか……！","ENG":"What?! Don't tell me you're...!","TWN":"啊，難道你是……！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};